"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[126],{9241:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new Track that animates `rig` using `keyframeSequence`.\\n\\n```lua\\nlocal track = Heln.new(workspace.MyRig, script.MyAnimation)\\n```","params":[{"name":"rig","desc":"Rig containing named Motor6D joints.","lua_type":"Model"},{"name":"keyframeSequence","desc":"Sequence to play.","lua_type":"KeyframeSequence"}],"returns":[{"desc":"","lua_type":"Track"}],"function_type":"static","source":{"line":47,"path":"docs/Heln.lua"}},{"name":"Play","desc":"Starts or re-fades the track. If the track is already playing, this\\nre-fades WeightCurrent toward `weight` instead of restarting.\\n\\n```lua\\ntrack:Play()\\n\\n-- fade in over 0.3s at half weight, double speed\\ntrack:Play(0.3, \\"Linear\\", 0.5, 2)\\n```","params":[{"name":"fadeTime","desc":"Seconds to blend weight. Defaults to instant.","lua_type":"number?"},{"name":"fadeStyle","desc":"\\"Linear\\", \\"Constant\\", \\"Elastic\\", \\"Cubic\\", or \\"Bounce\\". Defaults to \\"Linear\\".","lua_type":"string?"},{"name":"weight","desc":"Target blend weight. Defaults to the current WeightTarget.","lua_type":"number?"},{"name":"speed","desc":"Playback speed multiplier. Negative plays backward.","lua_type":"number?"}],"returns":[],"function_type":"method","source":{"line":68,"path":"docs/Heln.lua"}},{"name":"Pause","desc":"Freezes the track at its current TimePosition. Calling Play again resumes\\nfrom there.\\n\\n```lua\\ntrack:Pause()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":81,"path":"docs/Heln.lua"}},{"name":"Stop","desc":"Stops the track, honoring its PlaybackType. Persistent playback types hold\\ntheir current pose; reversible playback types begin playing backward\\ntoward time 0 or a marker before finishing.\\n\\n```lua\\ntrack:Stop()\\n\\n-- fade weight to 0 over half a second before stopping\\ntrack:Stop(0.5)\\n```","params":[{"name":"fadeTime","desc":"Seconds to fade weight to 0 before stopping. Defaults to instant.","lua_type":"number?"},{"name":"fadeStyle","desc":"Easing curve for the fade. Defaults to \\"Linear\\".","lua_type":"string?"}],"returns":[],"function_type":"method","source":{"line":101,"path":"docs/Heln.lua"}},{"name":"GetTimeOfKeyframe","desc":"Returns the time of a named keyframe from the sequence, or nil if no\\nkeyframe with that name exists.\\n\\n```lua\\nlocal time = track:GetTimeOfKeyframe(\\"Landed\\")\\n```","params":[{"name":"keyframeName","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"number?"}],"function_type":"method","source":{"line":117,"path":"docs/Heln.lua"}},{"name":"SetMarker","desc":"Adds a custom marker at `time`, independent of any Keyframe instance.\\nCustom markers are searched alongside keyframe-derived markers by\\nGetPreviousMarker, GetNextMarker, and GetNearestMarker, and fire\\nKeyframeReached the same way.\\n\\n```lua\\ntrack:SetMarker(0.4, \\"HitFrame\\")\\n```","params":[{"name":"time","desc":"","lua_type":"number"},{"name":"name","desc":"Defaults to an empty string.","lua_type":"string?"},{"name":"value","desc":"Payload passed to KeyframeReached and marker signals.","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":136,"path":"docs/Heln.lua"}},{"name":"GetPreviousMarker","desc":"Returns the closest marker (keyframe-derived or custom) strictly before\\n`fromTime`, or nil if there is none.\\n\\n```lua\\nlocal marker = track:GetPreviousMarker(1.0)\\n```","params":[{"name":"fromTime","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"Marker?"}],"function_type":"method","source":{"line":152,"path":"docs/Heln.lua"}},{"name":"GetNextMarker","desc":"Returns the closest marker strictly after `fromTime`, or nil if there is\\nnone.\\n\\n```lua\\nlocal marker = track:GetNextMarker(1.0)\\n```","params":[{"name":"fromTime","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"Marker?"}],"function_type":"method","source":{"line":168,"path":"docs/Heln.lua"}},{"name":"GetNearestMarker","desc":"Returns whichever marker is closest to `fromTime`, preferring the next\\nmarker on a tie.\\n\\n```lua\\nlocal marker = track:GetNearestMarker(1.0)\\n```","params":[{"name":"fromTime","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"Marker?"}],"function_type":"method","source":{"line":184,"path":"docs/Heln.lua"}},{"name":"GetMarkerReachedSignal","desc":"Returns a signal scoped to markers with the exact name `name`, created\\nlazily on first request.\\n\\n```lua\\ntrack:GetMarkerReachedSignal(\\"Footstep\\"):Connect(function(name, value)\\n    playFootstepSound(value)\\nend)\\n```","params":[{"name":"name","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Signal"}],"function_type":"method","source":{"line":202,"path":"docs/Heln.lua"}},{"name":"Destroy","desc":"Stops the track, unregisters it from the rig\'s update loop, and destroys\\nall of its signals, including any created via GetMarkerReachedSignal.\\nReading or writing properties on a destroyed track raises an error.\\n\\n```lua\\ntrack:Destroy()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":216,"path":"docs/Heln.lua"}}],"properties":[],"types":[],"name":"Heln","desc":"A multi-track animation controller for Roblox rigs.\\n\\nHeln reads a KeyframeSequence into per-joint timelines once, then evaluates\\nthose timelines against a Model\'s Motor6D joints every frame and writes\\ndirectly to Motor6D.Transform. This bypasses AnimationController and\\nAnimator, so animations do not need to be published as Roblox Animation\\nassets and can run on any rig with matching joint names.\\n\\nJoints are resolved by matching each Pose\'s name against Motor6D.Part1.Name\\non the rig, cached per rig and invalidated when a Motor6D is added or\\nremoved.\\n\\n```lua\\nlocal Heln = require(ReplicatedStorage.Heln)\\n\\nlocal track = Heln.new(rig, keyframeSequence)\\ntrack:Play()\\n\\ntrack.Ended:Connect(function()\\n    print(\\"done\\")\\nend)\\n```","source":{"line":31,"path":"docs/Heln.lua"}}')}}]);